// Valida o payload enviado pelo analisar.py e monta a linha no formato da planilha.
// Se faltar campo essencial, o erro aparece na execução e a resposta HTTP indica o problema.
const b = $input.first().json.body ?? $input.first().json;

const obrigatorios = ['nome_teste', 'parceiro', 'descricao', 'resultado', 'decisao'];
const faltando = obrigatorios.filter((c) => !b[c]);
if (faltando.length) {
  throw new Error('Payload incompleto, faltou: ' + faltando.join(', '));
}

const grupos = b.grupos
  ? Object.entries(b.grupos).map(([g, v]) => `${g}: ${String(v).replace('.', ',')}%`).join('; ')
  : '';

return [{
  json: {
    registrado_em: b.gerado_em ?? new Date().toISOString(),
    nome_teste: b.nome_teste,
    parceiro: b.parceiro,
    periodo: b.periodo ?? '',
    janela_valida: b.janela_valida ?? '',
    dias_validos: b.dias_validos ?? '',
    grupos_cashback: grupos,
    descricao: b.descricao,
    metrica_primaria: b.metrica_primaria ?? '',
    resultado: b.resultado,
    decisao: b.decisao,
    confianca: b.confianca ?? '',
    p_valor: typeof b.p_valor === 'number' && b.p_valor < 0.001 ? '<0,001' : (b.p_valor ?? ''),
    alertas: Array.isArray(b.alertas) ? (b.alertas.join('; ') || 'nenhum') : (b.alertas ?? 'nenhum'),
    relatorio: b.relatorio ?? ''
  }
}];

